var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……계획대로 최후의 발키리는 전장에서 축출되었습니다.","JPN":"……計画どおり、ラストヴァルキリーは戦場から追い出されました。","ENG":"...The Last Valkyrie has been expelled from the battlefield, as planned.","TWN":"……最後的女武神已經按照計畫被逐出戰場。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"비록 이 정도로 죽음을 맞을 리는 없으나…….","JPN":"この程度で死を迎えるはずはありませんが……","ENG":"Although this alone won’t be enough to end her...","TWN":"雖然她應該不太可能就這樣死掉……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그녀가 차원의 미로에서 빠져 나왔을 때면 이미 모든 것이 끝난 뒤겠지요.","JPN":"彼女が次元の迷路から抜け出たころには、もうすべて終わっているでしょう。","ENG":"By the time she escapes the maze of dimensions, this will all be over.","TWN":"但等她從次元迷宮中回來，一切應該都已經塵埃落定。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"동맹들 또한 약속한 대로 움직여 주고 있으니, 더 이상 저희의 진격을 막아설 자들은 없을 겁니다.","JPN":"同盟もまた約束どおり動いてくれているので、もう私たちの進撃を邪魔する者はいません。","ENG":"As our allies are also moving as promised, there will be nobody left to challenge our advance.","TWN":"結盟的人目前也照約定移動中，已經沒有人可以阻止我們進擊。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"후후, 그런데 참으로 재미있군요.","JPN":"ふふ、ところで本当に面白いですね。","ENG":"Fu fu, but how interesting.","TWN":"呵呵，不過真有意思呢。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"지난번 그녀에게 당당히 승부를 내자고 하셨던 전하 아니셨는지요?","JPN":"この前彼女に正々堂々勝負しようとおっしゃったのは殿下ではありませんでしたか？","ENG":"Wasn't it Your Highness who asked to challenge her to a fair fight next time? ","TWN":"上次說要和她光明正大一決勝負的人，不就是殿下嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"헌데 저와 같이 미천한 것을 끌어들여 모략으로 제거하려 하시다니요.","JPN":"なのに、私のような下賤な者を引き込み、謀略で取り除こうとなさるなんて。","ENG":"But now, you’re trying to eliminate her through schemes by involving a lowly being like me.","TWN":"現在卻跟我這種卑賤的人一起討論，要怎麼用計謀除掉她。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"혹여 전하께서도 그녀와 싸우는 것이 두려우셨습니까?","JPN":"もしや殿下も彼女と戦うことが恐ろしかったのですか？","ENG":"Have you become afraid of facing her?","TWN":"難道，殿下也害怕和她開戰嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그렇다. 두렵고 말고.","JPN":"そうだ。もちろん恐ろしい。","ENG":"Yes, you could say that I’m afraid.","TWN":"沒錯，我怕。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"...I beg your pardon?","TWN":"……什麼？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"의무를 짊어진다는 것은, 누군가의 희망을 대신한다는 것은.","JPN":"義務を背負うということは、誰かの希望を代わりにするということは。","ENG":"Taking responsibility means that you’re taking on somebody’s hope.","TWN":"背負義務，肩負某人的期待，"},"stage":{"bg":"MS_901","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 군림한다는 것은……","JPN":"そして君臨するということは……","ENG":"And to rule...","TWN":"還有做為一國之君……"},"stage":{"bg":"MS_901","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마땅히 무겁고도 두려운 일이지.","JPN":"当然重く恐ろしいことだ。","ENG":"It’s a heavy and dreadful task.","TWN":"都是令人感到沉重又戰兢的事情。"},"stage":{"bg":"MS_901","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그것을 이해하지 못하는 자는 결코 고귀한 혈통이 될 수 없다.","JPN":"それを理解できない者は決して尊き血統にはなれん。","ENG":"Those who do not understand this will never be worthy of the crown.","TWN":"無法理解這件事的人，是絕對無法繼承高貴的血統的。"},"stage":{"bg":"MS_901","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하물며 적이 두려워 도망치는 비겁함과 유리한 전장을 만드는 전략을 구분하지 못하는 자는 범상하다고도 할 수 없지.","JPN":"ましてや敵に恐れをなし逃げる卑怯さと、戦場を有利にする戦略を見分けられない者は平凡とも言えないのだ。","ENG":"On a similar note, those who cannot tell the difference between running in fear of an enemy and a tactical retreat cannot be considered anything more than mediocre.","TWN":"再者，因為畏敵而逃跑的懦弱，和打造有利戰場的戰略，這二者是不同的，竟然有人分不出來。"},"stage":{"bg":"MS_901","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"자, 그러니 대답해 보아라. 루크레시아.","JPN":"さあ、だから答えてみろ。ルクレシア。","ENG":"So tell me, Lucrecia.","TWN":"來，回答我，露可蕾西亞。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"적을 앞둔 선봉에서 하찮은 교만이나 부리려고 장수를 능멸하려는 자는 무엇이라 하겠느냐?","JPN":"敵を目の前にしている先鋒で、つまらない驕慢を振るうために将軍を侮辱しようとする者は何と呼ぶべきか？","ENG":"What would you call a fool who scorns the commander while facing an enemy merely to stroke her own ego?","TWN":"在臨陣之際展現無謂的驕傲，或是意圖羞辱將領之人的居心何在？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그, 그건…….","JPN":"そ、それは……","ENG":"Th-that’s...","TWN":"那個……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……큭!","JPN":"……くっ！","ENG":"Grr...!","TWN":"……咳！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"결국은 제 도움이나 받은 처지에 말씀이 지나치시군요!","JPN":"結局は私に助けてもらった立場なのに、言葉が過ぎますね！","ENG":"For someone needing my help, your choice of words displeases me!","TWN":"說到底，是殿下需要我的幫助，說這種話不會太過分嗎！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"저는 이만 성역으로 돌아가 보겠습니다.","JPN":"私はこれで聖域へ帰ります。","ENG":"I shall return to the sanctuary.","TWN":"請恕我先回聖域，"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이해도 못하는 전하의 책략을 위해 더 이상 힘을 쓰고 싶진 않네요.","JPN":"理解もできない殿下の策略のために、これ以上頑張りたくありません。","ENG":"I no longer wish to expend my efforts into your schemes which I do not understand.","TWN":"我不想再花力氣在殿下那無法理解的策略上。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하하, 그래. 지금은 돌아가 쉬어라.","JPN":"はは、そうか。今は帰って休むといい。","ENG":"Haha, as you wish. Return to the sanctuary and rest.","TWN":"哈哈，好，你先回去休息吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"전투가 끝나고 진혼의 시간이 오면 네가 필요해질 테니 말이다.","JPN":"戦闘が終わり、鎮魂の時が来ると貴様が必要になるだろうからな。","ENG":"I’ll need you for the Requiem after the battle.","TWN":"等戰爭結束後輪到安魂的時間時，再換你上場。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……집행할까요, 전하?","JPN":"……執行したしましょうか、殿下。","ENG":"...Shall I carry out the sentence, Your Highness?","TWN":"……殿下，行刑嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L34_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"무서운 말을 하는군, 마르티네즈 공.","JPN":"怖いことを言うな、マルチネス公。","ENG":"You're talking talking scary, Marquise Martinez.","TWN":"馬汀尼茲侯爵，你怎麼說出這麼可怕的話呢？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그녀에게서 무언가 불경한 흔적이라도 발견했느냐?","JPN":"彼女から何か不敬な痕跡でも発見したか？","ENG":"Did you detect any signs of corruption from her?","TWN":"你有發現到她有什麼不敬的行為嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그것은…… 그렇지 않습니다.","JPN":"それは……違います。","ENG":"Signs... No, I did not.","TWN":"這個……沒有。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"하오나 인형의 창조자와 지식의 탐식자에게 동맹을 청한 것 역시 그녀입니다.","JPN":"ですが、人形の創造者と知識の貪食者に同盟を申し出たのも彼女です。","ENG":"However, she is the one who requested an alliance with the Puppet Creator and Devourer of Knowledge.","TWN":"但是她說要和木偶的創造者和知識的貪食者結盟的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"인간의 동맹도 한 치 앞을 가늠할 수 없는데 마왕의 동맹은 말할 것 없지 않습니까?","JPN":"人間の同盟も一寸先を予想できないというのに、魔王との同盟はなおさらではありませんか。","ENG":"Even alliances with humans can be fickle. What can one expect from those made with Demon Lords?","TWN":"和人類結盟都會必有勝算，更何況是和魔王結盟？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"성녀의 미련한 판단 탓에 폐하의 옥체가 상하기라도 한다면, 저는 참지 못할 것입니다.","JPN":"聖女の愚かな判断のせいで陛下の玉体に傷でもついたら、私は我慢できません。","ENG":"Should the crown be defiled by to the Saintess’s foolish judgement, nothing will save her from my wrath.","TWN":"若是因為聖女愚蠢的判斷，而傷到陛下的龍體，那我就絕對無法忍受。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마르티네즈 공. 나는 그대가 가문의 주박에서 벗어나 기쁘다.","JPN":"マルチネス公。私は君が家門の呪縛から逃れたことが嬉しい。","ENG":"Marquise Martinez., I am glad that you have broken free from the leash set by your family.","TWN":"馬汀尼茲侯爵，我很高興你可以脫離家族的束縛。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"허나 나를 공의 또다른 가문으로 여기려 하지 마라.","JPN":"だが、私を公のもう一つの家門だとは考えるな。","ENG":"However, don’t consider me as another family of yours.","TWN":"但不要將我當作是你的另一個家族。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……죄송합니다.","JPN":"……申し訳ございません。","ENG":"...My apologies, Your Highness.","TWN":"……抱歉。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 너무 걱정할 필요는 없다.","JPN":"それに、そこまで心配する必要はあるまい。","ENG":"Also, you do not have to worry so much.","TWN":"另外，你不必擔心。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그녀는 참으로 미천하고 천박한 존재이지만……","JPN":"彼女はまこと下賤で軽薄な存在だが……","ENG":"She may be a truly lowly and vulgar individual...","TWN":"雖然她身分卑賤……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"우리 구원기사단의 일원임은 분명하니 말이다.","JPN":"我々救援騎士団の一員であることは確かだからな。","ENG":"But I do not doubt that she is a member of our Knights of Redemption.","TWN":"但她也是屬於我們救贖騎士團的一員。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};